files./src/Poll.js:
import React, { useState } from 'react';

export default function Poll({ question, options }) {
  const [votes, setVotes] = useState(options.map((o) => o.votes));
  const [choice, setChoice] = useState(null);

  const total = votes.reduce((a, b) => a + b, 0);
  const pct = (n) => (total === 0 ? 0 : Math.round((n / total) * 100));

  const vote = (i) => {
    setVotes((v) => {
      const next = v.slice();
      if (choice != null) next[choice] -= 1;
      next[i] += 1;
      return next;
    });
    setChoice(i);
  };

  return (
    <div style={{ maxWidth: 360 }}>
      <h3>{question}</h3>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
        {options.map((o, i) => (
          <button
            key={o.label}
            onClick={() => vote(i)}
            style={{ position: 'relative', textAlign: 'left', padding: '10px 14px', border: choice === i ? '2px solid #2563eb' : '1px solid #d1d5db', borderRadius: 8, background: '#fff', cursor: 'pointer', overflow: 'hidden' }}
          >
            {choice != null && (
              <span style={{ position: 'absolute', inset: 0, width: `${pct(votes[i])}%`, background: '#eff6ff', zIndex: 0 }} />
            )}
            <span style={{ position: 'relative', zIndex: 1, display: 'flex', justifyContent: 'space-between' }}>
              <span>{o.label}</span>
              {choice != null && <strong>{pct(votes[i])}%</strong>}
            </span>
          </button>
        ))}
      </div>
      <p style={{ color: '#888', marginTop: 10 }}>
        {choice != null ? `${total} votes` : 'Click an option to vote'}
      </p>
    </div>
  );
}

vue.answer:
## Building a Poll / Voting Widget in Vue 3

**Mental model:** A list of options with vote counts plus the user's current choice. Voting increments the picked option (and decrements the previous on a switch). Total and percentages are `computed`; results reveal only after voting.

### Step 1 — Counts + choice
```vue
<script setup>
import { ref, computed } from 'vue';
const votes = ref(props.options.map((o) => o.votes));
const choice = ref(null);
</script>
```

### Step 2 — Vote with switch support
```js
function vote(i) {
  const next = votes.value.slice();
  if (choice.value != null) next[choice.value]--;
  next[i]++;
  votes.value = next;
  choice.value = i;
}
```

### Step 3 — Derive total + percent
```js
const total = computed(() => votes.value.reduce((a, b) => a + b, 0));
const pct = (n) => (total.value === 0 ? 0 : Math.round((n / total.value) * 100));
```

### Step 4 — Reveal after voting
```vue
<span v-if="choice != null" :style="{ width: pct(votes[i]) + '%' }" />
```

**Edge cases**

| Case | Handling |
| :-- | :-- |
| Switch vote | Decrement old, increment new. |
| Zero total | Guard division. |
| Re-vote same | No-op. |

**Interview tip:** Vote-switching (decrement previous, increment new) is the modeling detail that enforces one-vote-per-user — a naive increment-only handler fails that requirement.

angular.answer:
## Building a Poll / Voting Widget in Angular

**Mental model:** Options with vote counts plus the user's choice. Voting increments the picked option (decrementing the previous on a switch). Total and percentages come from getters/methods; results reveal after voting. Classic `NgModule` setup, no `?.`/`??` (the build rejects them).

### Step 1 — Counts + choice
```typescript
@Input() options: PollOption[] = [];
votes: number[] = [];
choice: number | null = null;
ngOnInit(): void { this.votes = this.options.map((o) => o.votes); }
```

### Step 2 — Vote with switch support
```typescript
vote(i: number): void {
  const next = this.votes.slice();
  if (this.choice !== null) { next[this.choice]--; }
  next[i]++;
  this.votes = next;
  this.choice = i;
}
```

### Step 3 — Derive total + percent
```typescript
get total(): number { return this.votes.reduce((a, b) => a + b, 0); }
pct(n: number): number { return this.total === 0 ? 0 : Math.round((n / this.total) * 100); }
```

### Step 4 — Reveal after voting
```html
<span *ngIf="choice !== null" [style.width.%]="pct(votes[i])"></span>
```

**Edge cases**

| Case | Handling |
| :-- | :-- |
| Switch vote | Decrement old, increment new. |
| Zero total | Guard division. |
| Re-vote same | No-op. |

**Interview tip:** Modeling vote-switching (decrement previous + increment new) is what enforces one-vote-per-user; `[style.width.%]` is Angular's clean way to bind a percentage width for the result bars.

