import { Component, Input, OnInit } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface PollOption { label: string; votes: number; }

@Component({
  selector: 'app-poll',
  template: `
    <div style="max-width: 360px;">
      <h3>{{ question }}</h3>
      <div style="display: flex; flex-direction: column; gap: 10px;">
        <button
          *ngFor="let o of options; let i = index"
          (click)="vote(i)"
          [style.border]="choice === i ? '2px solid #2563eb' : '1px solid #d1d5db'"
          style="position: relative; text-align: left; padding: 10px 14px; border-radius: 8px; background: #fff; cursor: pointer; overflow: hidden;"
        >
          <span *ngIf="choice !== null" [style.width.%]="pct(votes[i])" style="position: absolute; inset: 0; background: #eff6ff; z-index: 0;"></span>
          <span style="position: relative; z-index: 1; display: flex; justify-content: space-between;">
            <span>{{ o.label }}</span>
            <strong *ngIf="choice !== null">{{ pct(votes[i]) }}%</strong>
          </span>
        </button>
      </div>
      <p style="color: #888; margin-top: 10px;">{{ choice !== null ? total + ' votes' : 'Click an option to vote' }}</p>
    </div>
  `,
})
export class PollComponent implements OnInit {
  @Input() question = '';
  @Input() options: PollOption[] = [];
  votes: number[] = [];
  choice: number | null = null;

  ngOnInit(): void {
    this.votes = this.options.map((o) => o.votes);
  }

  get total(): number {
    return this.votes.reduce((a, b) => a + b, 0);
  }

  pct(n: number): number {
    return this.total === 0 ? 0 : Math.round((n / this.total) * 100);
  }

  vote(i: number): void {
    const next = this.votes.slice();
    if (this.choice !== null) {
      next[this.choice]--;
    }
    next[i]++;
    this.votes = next;
    this.choice = i;
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Poll Demo</h1>
      <app-poll question="Favorite framework?" [options]="options"></app-poll>
    </div>
  `,
})
export class AppComponent {
  options: PollOption[] = [
    { label: 'React', votes: 42 },
    { label: 'Vue', votes: 28 },
    { label: 'Angular', votes: 19 },
    { label: 'Svelte', votes: 11 },
  ];
}

@NgModule({
  declarations: [AppComponent, PollComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
